{
  "sentences": [
    {
      "text": "請問洗手間在哪裡？",
      "pinyin": "Qǐngwèn xǐshǒujiān zài nǎlǐ?",
      "pinyin_numeric": "qing3 wen4 xi3 shou3 jian1 zai4 na3 li3",
      "translation_en": "Excuse me, where is the restroom?",
      "translation_ko": "실례합니다, 화장실이 어디에 있나요?"
    },
    {
      "text": "電梯在左邊嗎？",
      "pinyin": "Diàntī zài zuǒbiān ma?",
      "pinyin_numeric": "dian4 ti1 zai4 zuo3 bian1 ma0",
      "translation_en": "Is the elevator on the left?",
      "translation_ko": "엘리베이터가 왼쪽에 있나요?"
    },
    {
      "text": "出口在二樓的後面。",
      "pinyin": "Chūkǒu zài èr lóu de hòumiàn.",
      "pinyin_numeric": "chu1 kou3 zai4 er4 lou2 de0 hou4 mian4",
      "translation_en": "The exit is at the back of the second floor.",
      "translation_ko": "출구는 2층 뒤쪽에 있습니다."
    },
    {
      "text": "櫃台在入口的旁邊。",
      "pinyin": "Guìtái zài rùkǒu de pángbiān.",
      "pinyin_numeric": "gui4 tai2 zai4 ru4 kou3 de0 pang2 bian1",
      "translation_en": "The counter is next to the entrance.",
      "translation_ko": "카운터는 입구 옆에 있습니다."
    },
    {
      "text": "教室在三樓嗎？",
      "pinyin": "Jiàoshì zài sān lóu ma?",
      "pinyin_numeric": "jiao4 shi4 zai4 san1 lou2 ma0",
      "translation_en": "Is the classroom on the third floor?",
      "translation_ko": "교실은 3층에 있나요?"
    },
    {
      "text": "辦公室在一樓的右邊。",
      "pinyin": "Bàngōngshì zài yī lóu de yòubiān.",
      "pinyin_numeric": "ban4 gong1 shi4 zai4 yi1 lou2 de0 you4 bian1",
      "translation_en": "The office is on the right side of the first floor.",
      "translation_ko": "사무실은 1층 오른쪽에 있습니다."
    },
    {
      "text": "請問樓梯在哪裡？",
      "pinyin": "Qǐngwèn lóutī zài nǎlǐ?",
      "pinyin_numeric": "qing3 wen4 lou2 ti1 zai4 na3 li3",
      "translation_en": "Excuse me, where are the stairs?",
      "translation_ko": "실례합니다, 계단이 어디에 있나요?"
    },
    {
      "text": "服務台在櫃台的前面嗎？",
      "pinyin": "Fúwùtái zài guìtái de qiánmiàn ma?",
      "pinyin_numeric": "fu2 wu4 tai2 zai4 gui4 tai2 de0 qian2 mian4 ma0",
      "translation_en": "Is the service desk in front of the counter?",
      "translation_ko": "서비스 데스크가 카운터 앞에 있나요?"
    },
    {
      "text": "手扶梯在電梯的旁邊。",
      "pinyin": "Shǒufútī zài diàntī de pángbiān.",
      "pinyin_numeric": "shou3 fu2 ti1 zai4 dian4 ti1 de0 pang2 bian1",
      "translation_en": "The escalator is next to the elevator.",
      "translation_ko": "에스컬레이터는 엘리베이터 옆에 있습니다."
    },
    {
      "text": "教室在走廊的中間。",
      "pinyin": "Jiàoshì zài zǒuláng de zhōngjiān.",
      "pinyin_numeric": "jiao4 shi4 zai4 zou3 lang2 de0 zhong1 jian1",
      "translation_en": "The classroom is in the middle of the hallway.",
      "translation_ko": "교실은 복도 중간에 있습니다."
    }
  ]
}
